INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (14, '0101000020E6100000982DA8018FC453C02F8DD11C5F8A4540', 12, 'La zone Power Portal à coté des chutes du Niagara à un taux élevé de pollution en journée avec toutes les voitures des touristes.');
INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (15, '0101000020E610000095F2534928C553C08F248095D9894540', 13, 'Parking avec taux moyen de CO2 détecté le matin et le soir principalement.');
INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (16, '0101000020E61000002AABD8C336C453C05AE3E3F6E7894540', 14, 'Zone avec faible pollution en raison des chutes d''eau à proximité.');
INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (17, '0101000020E610000008B1DD372CC453C05EBA5ADE558A4540', 15, 'Zone Goat Island avec un taux élevé d''émition de CO2 le matin et le soir.');
INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (19, '0101000020E6100000BBEE1A96ECC353C0BC47252E2F8A4540', 17, 'Parking avec un taux élevé de CO2 en été en raison de l''affluence de touriste.');
INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (22, '0101000020E6100000A3186CF9B4C453C0D20FBD20408A4540', 20, 'Cette zone à une qualité de l''air mauvaise en été.

Cela est dû à l''augmentation des bateaux à moteurs pour les touristes à proximités, ainsi qu''aux bateaux de pêches affluant ici chaque été.');
INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (23, '0101000020E6100000BEF110A4EEC453C096CD24A10E884540', 21, 'Ce parc à bcp de pollution pendant les vacances, en raison du nombre croissant de voitures à proximités.

La période ayant le plus haut niveau de pollution est durant le mois d''Aout.');
INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (24, '0101000020E6100000C7B1892164C453C0FED9A16A9A8A4540', 22, 'Cette zone à un niveau de pollution élevé à partir de 18h tous les soirs.');
INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (25, '0101000020E610000072B00D137DBF53C05EC23429718A4540', 23, 'Test de filtre.');
INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (26, '0101000020E610000023FE0B6634C353C0D5A1F98EE98B4540', 24, 'Beaucoup de CO2 émis à proximité de l''hopital');
INSERT INTO public."pointAndDescriptionUser" OVERRIDING SYSTEM VALUE VALUES (27, '0101000020E61000007DBF75EA07C553C01892621A61764540', 25, 'Beaucoup de CO2 diffusé chaque jour, en raison des avions qui atterrissent ici régulièrement.');


